      case Keyword.get(opts, :renew) do
        true -> 
          SessionStore.delete(conn.private[:session_id])
          new_id = generate_session_id()
          put_private(conn, :session_id, new_id)
          session
        _ -> 
          session
      end
    
    put_private(conn, :session, updated_session)
  end

  defp get_session_id(conn) do
    case fetch_cookies(conn).cookies[@cookie_name] do
      nil -> generate_session_id()
      id -> id
    end
  end

